	public void UpdateState(PurchaseConsoleBuiState state)
	{
		_catalog = state.Catalog;
		_pendingRequests = state.PendingRequests;
		_isLeader = state.IsLeader;
		_availablePoints = state.AvailablePoints;
		PointsLabel.Text = Loc.GetString("civ-purchase-console-points", new(string, object)[1] { ("points", _availablePoints) });
		((Control)RequestsTab).Visible = _isLeader;
		if (_isLeader && _pendingRequests.Count > 0)
		{
			((Control)RequestsBadge).Visible = true;
			RequestsBadge.Text = $"({_pendingRequests.Count})";
		}
		else
		{
			((Control)RequestsBadge).Visible = false;
		}
		if (_currentCategory != "Все" && !_catalog.ContainsKey(_currentCategory))
		{
			_currentCategory = "Все";
		}
		RebuildCategoryButtons();
		RefreshCatalog();
		RefreshRequests();
		RefreshCart();
	}

