	private void AddToCart(CatalogItem item)
	{
		CartEntry cartEntry = _cart.FirstOrDefault((CartEntry e) => e.ItemId == item.ItemPrototype);
		if (cartEntry != null)
		{
			if (item.IsWeapon)
			{
				return;
			}
			cartEntry.Quantity += item.PackQuantity;
		}
		else
		{
			_cart.Add(new CartEntry
			{
				ItemId = item.ItemPrototype,
				ItemName = item.Name,
				Quantity = (item.IsWeapon ? 1 : item.PackQuantity),
				UnitPrice = item.Price,
				PackQuantity = item.PackQuantity,
				IsWeapon = item.IsWeapon
			});
			_cartItemIds.Add(item.ItemPrototype);
		}
		RefreshCart();
		RefreshCatalog();
	}

