	private void IncreaseQuantity(CartEntry entry)
	{
		if (!entry.IsWeapon)
		{
			entry.Quantity += entry.PackQuantity;
			RefreshCart();
		}
	}

	private void DecreaseQuantity(CartEntry entry)
	{
		entry.Quantity -= entry.PackQuantity;
		if (entry.Quantity <= 0)
		{
			_cart.Remove(entry);
			_cartItemIds.Remove(entry.ItemId);
			RefreshCatalog();
		}
		RefreshCart();
	}

	private void OnClearClicked()
	{
		if (_cart.Count != 0)
		{
			if (_confirmingClear)
			{
				_confirmingClear = false;
				ClearCart();
			}
			else
			{
				_confirmingClear = true;
				RefreshCart();
			}
		}
	}

	private void ClearCart()
	{
		_cart.Clear();
		_cartItemIds.Clear();
		_confirmingClear = false;
		RefreshCart();
		RefreshCatalog();
	}

	private void OnSubmitClicked()
	{
		if (_cart.Count != 0)
		{
			List<PurchaseItem> obj = _cart.Select((CartEntry e) => new PurchaseItem
			{
				ItemId = e.ItemId,
				ItemName = e.ItemName,
				Quantity = e.Quantity,
				UnitPrice = e.UnitPrice
			}).ToList();
			this.OnPurchaseSubmit?.Invoke(obj);
			ClearCart();
		}
	}

